module top_module(
    q,
    clk,
    rst
);output reg [3:0] q;
    input clk;
    input rst;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst) begin
            q <= 4'b0000;
        end else begin
            q <= q + 1;
            if (q == 4'b1111) begin
                q <= 4'b0000;
            end
        end
    end

endmodule
